public void dialog()
{
    Dialog                       dialog;
    TransDate                    fromDate,toDate;
    DialogField                  dialogFromDate,dialogToDate;
    DialogField                  dialogCustomerBalance;
    dialog = new dialog("Customer open transactions");
    dialogFromDate       = dialog.addField(extendedTypeStr(TransDate), "As of date");
   // dialogCustomerBalance         = dialog.addField(enumStr(NoYes), "Customer balance");
    dialog.run();
    if(dialogFromDate.value() >= today())
    {
        throw error("As of date should not be greater than Today's date'");
    }
    else if (dialog.run())
    {
        this.createCustOpenTransData(dialogFromDate.value());
    }
}

/// <summary>
///
/// </summary>
/// <param name = "_fromdate"></param>
/// <param name = "_todate"></param>
public void createCustOpenTransData(date _fromdate)
{
    ETGCustOpenTrans custOpenTrans;
    CustTrans custTrans;
    CustTable custTable;
    date fromdate, todate;
    timeofday fromtime, totime;

    str businessUnitValue, profitCenterValue, projectValue, product_ServiceValue,verticalValue,
        MAIN_COMMODITYValue, SUB_COMMODITYValue, lineOfBusinessValue, contractValue, plantWarehouseOfficeValue,
        departmentValue, interCompanyValue, trader_EmployeeValue, itemValue;
    str businessUnitStr = "BusinessUnit";
    str profitCenterStr = "ProfitCenter";
    str projectStr = "Project";
    str product_ServiceStr = "Product_Service";
    str verticalStr = "Vertical";
    str MAIN_COMMODITYStr = "MainCommodity";
    str SUB_COMMODITYStr = "SubCommodity";
    str lineOfBusinessStr = "Line_of_Business";
    str contractsStr = "Contract";
    str plantWarehouseOfficeStr = "Plant_Warehouse_Office";
    str departmentStr = "Department";
    str interCompanyStr = "InterCompany";
    str trader_EmployeeStr = "Trader_Employee";
    str itemStr = "Item";

    Args args = new Args();
    ;
    ttsbegin;
    delete_from custOpenTrans;
    ttscommit;

    while select custTrans 
        where custTrans.DataAreaId == curext()
        && custTrans.TransDate <= _fromdate
        && (custTrans.Closed == dateNull()
        || custTrans.Closed <= _fromdate)

    if(custTrans)
    {
        custOpenTrans.PostingProfileClose = custTrans.PostingProfileClose;
        custOpenTrans.AccountingEvent = custTrans.AccountingEvent;            
        custOpenTrans.AccountNum = custTrans.AccountNum;            
        custOpenTrans.AmountCur = custTrans.AmountCur - custTrans.SettleAmountCur;
        custOpenTrans.AmountMST = custTrans.AmountMST - custTrans.SettleAmountMST;
        custOpenTrans.Approved = custTrans.Approved;
        custOpenTrans.Approver = custTrans.Approver;
        custOpenTrans.BankCentralBankPurposeCode = custTrans.BankCentralBankPurposeCode;
        custOpenTrans.BankCentralBankPurposeText = custTrans.BankCentralBankPurposeText;
        custOpenTrans.BankLCExportLine = custTrans.BankLCExportLine;
        custOpenTrans.BankRemittanceFileId = custTrans.BankRemittanceFileId;
        custOpenTrans.BillOfExchangeID = custTrans.BillOfExchangeID;
        custOpenTrans.BillOfExchangeSeqNum = custTrans.BillOfExchangeSeqNum;
        custOpenTrans.BillOfExchangeStatus = custTrans.BillOfExchangeStatus;
        custOpenTrans.CancelledPayment = custTrans.CancelledPayment;
        custOpenTrans.CashDiscCode = custTrans.CashDiscCode;
        custOpenTrans.CashDiscBaseDate = custTrans.CashDiscBaseDate;
        custOpenTrans.CashPayment = custTrans.CashPayment;
        custOpenTrans.Closed = custTrans.Closed;
        custOpenTrans.CollectionLetter = custTrans.CollectionLetter;
        custOpenTrans.CollectionLetterCode = custTrans.CollectionLetterCode;
        custOpenTrans.CompanyBankAccountId = custTrans.CompanyBankAccountId;
        custOpenTrans.ControlNum = custTrans.ControlNum;
        custOpenTrans.Correct = custTrans.Correct;
        custOpenTrans.CurrencyCode = custTrans.CurrencyCode;
        custOpenTrans.CustBillingClassification = custTrans.CustBillingClassification;
        custOpenTrans.CustExchAdjustmentRealized = custTrans.CustExchAdjustmentRealized;
        custOpenTrans.CustExchAdjustmentUnrealized = custTrans.CustExchAdjustmentUnrealized;
        custOpenTrans.DefaultDimension = custTrans.DefaultDimension;
        custOpenTrans.DeliveryMode = custTrans.DeliveryMode;
        custOpenTrans.DirectDebitMandate = custTrans.DirectDebitMandate;
        custOpenTrans.DocumentDate = custTrans.DocumentDate;
        custOpenTrans.DocumentNum = custTrans.DocumentNum;
        custOpenTrans.DueDate = custTrans.DueDate;
        custOpenTrans.EUROTriangulation = custTrans.EUROTriangulation;
        custOpenTrans.ExchAdjustment = custTrans.ExchAdjustment;
        custOpenTrans.ExchAdjustmentReporting = custTrans.ExchAdjustmentReporting;
        custOpenTrans.ExchRate = custTrans.ExchRate;
        custOpenTrans.ExchRateSecond = custTrans.ExchRateSecond;
        custOpenTrans.FixedExchRate = custTrans.FixedExchRate;
        custOpenTrans.Interest = custTrans.Interest;
        custOpenTrans.Invoice = custTrans.Invoice;            
        custOpenTrans.InvoiceProject = custTrans.InvoiceProject;
        custOpenTrans.LastExchAdj = custTrans.LastExchAdj;
        custOpenTrans.LastExchAdjRate = custTrans.LastExchAdjRate;
        custOpenTrans.LastExchAdjRateReporting = custTrans.LastExchAdjRateReporting;
        custOpenTrans.LastExchAdjVoucher = custTrans.LastExchAdjVoucher;
        custOpenTrans.LastSettleAccountNum = custTrans.LastSettleAccountNum;
        custOpenTrans.LastSettleCompany = custTrans.LastSettleCompany;
        custOpenTrans.LastSettleDate = custTrans.LastSettleDate;
        custOpenTrans.LastSettleVoucher = custTrans.LastSettleVoucher;
        custOpenTrans.MCRPaymOrderID = custtrans.MCRPaymOrderID;
        custopentrans.OffsetRecid = custTrans.OffsetRecid;
        custOpenTrans.OrderAccount = custTrans.OrderAccount;
        custOpenTrans.PackedExtensions = custTrans.PackedExtensions;
        custOpenTrans.PaymId = custTrans.PaymId;
        custOpenTrans.PaymMethod = custTrans.PaymMethod;
        custOpenTrans.PaymMode = custTrans.PaymMode;
        custOpenTrans.PaymReference = custTrans.PaymReference;
        custOpenTrans.PaymSpec = custTrans.PaymSpec;
        custOpenTrans.PostingProfile = custTrans.PostingProfile;
        custOpenTrans.Prepayment = custTrans.Prepayment;
        custOpenTrans.ReasonRefRecId = custTrans.ReasonRefRecId;
        custOpenTrans.ReportingCurrencyAmount = custTrans.ReportingCurrencyAmount;
        custOpenTrans.ReportingCurrencyCrossRate = custTrans.ReportingCurrencyCrossRate;
        custOpenTrans.ReportingCurrencyExchRate = custTrans.ReportingCurrencyExchRate;
        custOpenTrans.ReportingCurrencyExchRateSecondary = custTrans.ReportingCurrencyExchRateSecondary;
        custOpenTrans.ReportingExchAdjustmentRealized = custTrans.ReportingExchAdjustmentRealized;
        custOpenTrans.ReportingExchAdjustmentUnrealized = custTrans.ReportingExchAdjustmentUnrealized;
        custOpenTrans.RetailCustTrans = custTrans.RetailCustTrans;
        custOpenTrans.RetailStoreId = custTrans.RetailStoreId;
        custOpenTrans.RetailTerminalId = custTrans.RetailTerminalId;
        custOpenTrans.RetailTransactionId = custTrans.RetailTransactionId;
        custOpenTrans.SettleAmountCur = custTrans.SettleAmountCur;
        custOpenTrans.SettleAmountMST = custTrans.SettleAmountMST;
        custOpenTrans.SettleAmountReporting = custTrans.SettleAmountReporting;
        custOpenTrans.Settlement = custTrans.Settlement;
        custOpenTrans.TaxInvoiceSalesId = custTrans.TaxInvoiceSalesId;
        custOpenTrans.ThirdPartyBankAccountId = custTrans.ThirdPartyBankAccountId;
        custOpenTrans.TransDate = custTrans.TransDate;
        custOpenTrans.TransType = custTrans.TransType;
        custOpenTrans.Txt = custTrans.Txt;
        custOpenTrans.Voucher = custTrans.Voucher;
        custOpenTrans.PaymSchedId = custTrans.PaymSchedId;
        custOpenTrans.PaymTermId = custTrans.PaymTermId;
        custOpenTrans.CustAutomationExclude = custTrans.CustAutomationExclude;
        custOpenTrans.CustAutomationPredunningSent = custTrans.CustAutomationPredunningSent;
        custOpenTrans.CustAutomationPredictionSent = custTrans.CustAutomationPredictionSent;
        custOpenTrans.SettleAmount_MX = custTrans.SettleAmount_MX;
        custOpenTrans.CustName = custTrans.custTableName();

        select * from custTable where custTable.AccountNum == custTrans.AccountNum;

        custOpenTrans.CustGroup = custTable.CustGroup;

        businessUnitValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, businessUnitStr);

        if(businessUnitValue)
        {
            custOpenTrans.BusinessUnit = businessUnitValue;
        }
        profitCenterValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, profitCenterStr);

        if(profitCenterValue)
        {
            custOpenTrans.ProfitCenter = profitCenterValue;
        }
        projectValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, projectStr);

        if(projectValue)
        {
            custOpenTrans.Project = projectValue;
        }
        product_ServiceValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, product_ServiceStr);

        if(product_ServiceValue)
        {
            custOpenTrans.Product_Service = product_ServiceValue;
        }
        verticalValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, verticalStr);

        if(verticalValue)
        {
            custOpenTrans.Vertical = verticalValue;
        }

        MAIN_COMMODITYValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, MAIN_COMMODITYStr);

        if(MAIN_COMMODITYValue)
        {
            custOpenTrans.MainCommodity = MAIN_COMMODITYValue;
        }

        SUB_COMMODITYValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, SUB_COMMODITYStr);

        if(SUB_COMMODITYValue)
        {
            custOpenTrans.SubCommodity = SUB_COMMODITYValue;
        }

        lineOfBusinessValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, lineOfBusinessStr);

        if(lineOfBusinessValue)
        {
            custOpenTrans.LineOfBusiness = lineOfBusinessValue;
        }

        contractValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, contractsStr);

        if(contractValue)
        {
            custOpenTrans.Contract = contractValue;
        }

        plantWarehouseOfficeValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, plantWarehouseOfficeStr);

        if(plantWarehouseOfficeValue)
        {
            custOpenTrans.PlantWarehouseOffice = plantWarehouseOfficeValue;
        }

        departmentValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, departmentStr);

        if(departmentValue)
        {
            custOpenTrans.Department = departmentValue;
        }

        interCompanyValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, interCompanyStr);

        if(interCompanyValue)
        {
            custOpenTrans.InterCompany = interCompanyValue;
        }

        trader_EmployeeValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, trader_EmployeeStr);

        if(trader_EmployeeValue)
        {
            custOpenTrans.TraderEmployee = trader_EmployeeValue;
        }

        itemValue = ETGBankTransFinDim::getDimensionDisplayValue(custTrans.DefaultDimension, itemStr);

        if(itemValue)
        {
            custOpenTrans.Item = itemValue;
        }

         custOpenTrans.ETGBalanceTC = custTrans.AmountCur - custTrans.SettleAmountCur;

            if(custTrans.LastExchAdjRate)
            {                  
               custOpenTrans.ETGNewExchRate = custTrans.LastExchAdjRate;
               custOpenTrans.ETGBalanceUSD = custOpenTrans.ETGBalanceTC * custTrans.LastExchAdjRate;
            }
            else
            {
                custOpenTrans.ETGNewExchRate = custTrans.ExchRate/100;
                custOpenTrans.ETGBalanceUSD = custOpenTrans.ETGBalanceTC * custOpenTrans.ETGNewExchRate;
            }

        custOpenTrans.insert();
    }
    new MenuFunction(menuItemdisplayStr(ETGCustOpenTrans),MenuItemType::Display).run();
}

/// <summary>
///
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGCustomerOpenTrans customerOpenTrans;
    customerOpenTrans = new ETGCustomerOpenTrans();
    customerOpenTrans.run();
}
